from matplotlib import pyplot as pltimport numpy as npimport cv2im1 = cv2.imread("../data/monkey.jpg")#image to referenceim2 =cv2.imread("../data/monkey_distorted.jpg")#image to be registeredimg1 = cv2.cvtColor(im1, cv2.COLOR_BGR2GRAY)img2 = cv2.cvtColor(im2, cv2.COLOR_BGR2GRAY)#Initiate ORBorb = cv2.ORB_create(50)kp1, des1 = orb.detectAndCompute(img1, None)kp2, des2 = orb.detectAndCompute(img2, None)matcher = cv2.DescriptorMatcher_create(cv2.DESCRIPTOR_MATCHER_BRUTEFORCE_HAMMING)#Match des1 des2 descriptorsmatches = matcher.match(des1, des2, None)matches = sorted(matches, key = lambda x:x.distance)img3 = cv2.drawKeypoints(img1, kp1, None, flags = None)img4 = cv2.drawKeypoints(img2, kp2, None, flags = None)points1 = np.zeros((len(matches), 2), dtype=np.float32)  #Prints empty array of size equal to (matches, 2)points2 = np.zeros((len(matches), 2), dtype=np.float32)for i, match in enumerate(matches):   points1[i, :] = kp1[match.queryIdx].pt    #gives index of the descriptor in the list of query descriptors   points2[i, :] = kp2[match.trainIdx].pt    #gives index of the descriptor in the list of train descriptors#Now we have all good keypoints so we are ready for homography.# Find homography#https://en.wikipedia.org/wiki/Homography_(computer_vision)h, mask = cv2.findHomography(points1, points2, cv2.RANSAC)plt.figure(figsize = (8,8))plt.subplot(1,2,1)plt.imshow(img3)plt.title("Image1")plt.subplot(1,2,2)plt.imshow(img4)plt.title("Image2")img5 = cv2.drawMatches(img1, kp1, img2, kp2, matches[:10], None)plt.figure(figsize = (8,8))plt.subplot(1,2,1)plt.imshow(img5)plt.show()height, width, channels = im2.shapeim1Reg = cv2.warpPerspective(im1, h, (width, height))  #Applies a perspective transformation to an image.print("Estimated homography : \n",  h)